local MIN_SPEED = 0.1 local function GetBonus(self) local bonus = self.inst:GetCharacterBonus( "speed" ) local bonusPercentage = self.inst:GetCharacterBonus( "speed_percent" ) local percentage2 = 0x0 local cripple = self.inst:GetCharacterBonus( "cripple" ) if cripple > 0x0 then bonus = 0x0 bonusPercentage = 0x0 percentage2 = - 0.75 end return bonus, bonusPercentage, percentage2 end local function DYCGetWalkSpeed(self, ...) local speed = self.dycOldGetWalkSpeed(self, ...) local speedDef = self.walkspeed or 0x0 local speedAdd = self.GetSpeedAdditive and self:GetSpeedAdditive() or 0x0 local bonus, bonusPercentage, percentage2 = GetBonus(self) speed = math.max(percentage2 ~= 0x0 and speedDef * (0x1 + percentage2) or speed + bonus + (speedDef + speedAdd) * bonusPercentage, MIN_SPEED) return speed, speedDef, speed - speedDef end local function DYCGetRunSpeed(self, ...) local speed = self.dycOldGetRunSpeed(self, ...) local speedDef = self.runspeed or 0x0 local speedAdd = self.GetSpeedAdditive and self:GetSpeedAdditive() or 0x0 local bonus, bonusPercentage, percentage2 = GetBonus(self) speed = math.max(percentage2 ~= 0x0 and speedDef * (0x1 + percentage2) or speed + bonus + (speedDef + speedAdd) * bonusPercentage, MIN_SPEED) return speed, speedDef, speed - speedDef end local function GetWalkSpeed(self, ...) local speed = self.dycOldGetWalkSpeed(self, ...) local speedDef = self.walkspeed or 0x0 local speedAdd = self.GetSpeedAdditive and self:GetSpeedAdditive() or 0x0 local bonus, bonusPercentage, percentage2 = GetBonus(self) speed = math.max(percentage2 ~= 0x0 and speedDef * (0x1 + percentage2) or speed + bonus + (speedDef + speedAdd) * bonusPercentage, MIN_SPEED) return speed end local function GetRunSpeed(self, ...) local speed = self.dycOldGetRunSpeed(self, ...) local speedDef = self.runspeed or 0x0 local speedAdd = self.GetSpeedAdditive and self:GetSpeedAdditive() or 0x0 local bonus, bonusPercentage, percentage2 = GetBonus(self) speed = math.max(percentage2 ~= 0x0 and speedDef * (0x1 + percentage2) or speed + bonus + (speedDef + speedAdd) * bonusPercentage, MIN_SPEED) return speed end local function OnUpdate(self, dt, ...) local result = self.dycOldOnUpdate(self, dt, ...) local cur_speed = self.inst.Physics and self.inst.Physics:GetMotorSpeed() or 0x0 if not self.hasmomentum and cur_speed > 0x0 then local speed_mult = self:GetSpeedMultiplier() or 0x1 if self.dest and self.dest:IsValid() then local destpos_x, destpos_y, destpos_z = self.dest:GetPoint() local mypos_x, mypos_y, mypos_z = self.inst.Transform:GetWorldPosition() local dsq = distsq(destpos_x, destpos_z, mypos_x, mypos_z) or 0x0 if dsq <= .25 then speed_mult = math.max(.33, math.sqrt(dsq)) end end local desired_speed = self.isrunning and self.runspeed or self.walkspeed or 0x0 local speedDef = self.isrunning and self.runspeed or self.walkspeed or 0x0 local speedAdd = self.GetSpeedAdditive and self:GetSpeedAdditive() or 0x0 local bonus, bonusPercentage, percentage2 = GetBonus(self) local speed = (desired_speed + self.bonusspeed + (self.GetSpeedBoost and self:GetSpeedBoost() or 0x0) + (self.GetSpeedAdditive and self:GetSpeedAdditive() or 0x0)) * speed_mult speed = math.max(percentage2 ~= 0x0 and speedDef * (0x1 + percentage2) or speed + bonus + (speedDef + speedAdd) * bonusPercentage, MIN_SPEED) self.inst.Physics:SetMotorVel(speed, 0x0, 0x0) end end local function DYCLocomotor(self) self.dycOldOnUpdate = self.OnUpdate self.OnUpdate = OnUpdate self.dycOldGetWalkSpeed = self.GetWalkSpeed self.GetWalkSpeed = GetWalkSpeed self.dycOldGetRunSpeed = self.GetRunSpeed self.GetRunSpeed = GetRunSpeed self.DYCGetWalkSpeed = DYCGetWalkSpeed self.DYCGetRunSpeed = DYCGetRunSpeed end return DYCLocomotor 